sql:
SELECT inst_nm
FROM institutions
WHERE inst_id = 1;

SELECT AVG(tuition_fee) AS average_tuition_fee
FROM programs
WHERE prog_type = 'undergraduate' AND accreditation_status = 'accredited';

external_knowledge:
'Generous with admissions' refers to institutions with a high average acceptance rate, meaning they accept a larger percentage of their applicants; 
In this context, the year 2022 is the specific time frame for which the data is analyzed;
'Top five' indicates the limit of the result set to five entries based on the highest average acceptance rate.

sql:
SELECT acceptance_rate, yield_rate
FROM admissions
WHERE year = '2022';

SELECT SUM(total_enrollment) AS total_hbcu_enrollment
FROM institutions
WHERE hbcu = 1;

SELECT inst_id, net_price
FROM financial_aid
ORDER BY net_price DESC;

SELECT i.inst_nm, a.satvrmid, a.satmtmid, a.acceptance_rate
FROM admissions a
JOIN institutions i ON a.inst_id = i.inst_id;
